  '{"family":{"status":"Single, lives with roommates","background":"Suburban, parents are divorced, close to mom","financial_support":true,"pressure":"Student debt anxiety, climate anxiety, career uncertainty"},"social_circle":{"primary":"College friends, TikTok community, activism groups","influencers":["Emma Chamberlain","Greta Thunberg","Various TikTok creators"],"trust_sources":["TikTok/YouTube reviews","peer recommendations","brand transparency reports"]},"relationships_with_products":{"adoption_path":"Discovers through social media, judges by brand values","referral_tendency":"very high","community_influence":"high"}}'::jsonb,
